/**
 * Tests for Notification Service
 */

import AsyncStorage from "@react-native-async-storage/async-storage";
import { apiFetch } from "../../services/api";
import {
  getNotifications,
  markAsRead,
  markAllAsRead,
  deleteNotification,
  getUnreadCount,
  updateSettings,
  getSettings,
  subscribeToTopic,
  unsubscribeFromTopic,
} from "../../services/notificationService";

// Mock dependencies
jest.mock("@react-native-async-storage/async-storage", () => ({
  getItem: jest.fn(),
  setItem: jest.fn(),
  removeItem: jest.fn(),
}));

jest.mock("../../services/api", () => ({
  apiFetch: jest.fn(),
}));

describe("notificationService", () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe("getNotifications", () => {
    it("should fetch notifications with pagination", async () => {
      const mockNotifications = {
        data: [
          { id: "1", title: "Test", message: "Message", read: false },
          { id: "2", title: "Test 2", message: "Message 2", read: true },
        ],
        total: 2,
        page: 1,
        limit: 20,
      };

      (apiFetch as jest.Mock).mockResolvedValue(mockNotifications);

      const result = await getNotifications({ page: 1, limit: 20 });

      expect(apiFetch).toHaveBeenCalledWith(
        expect.stringContaining("/notifications"),
        expect.any(Object),
      );
      expect(result.data).toHaveLength(2);
    });

    it("should filter by read status", async () => {
      (apiFetch as jest.Mock).mockResolvedValue({ data: [], total: 0 });

      await getNotifications({ unreadOnly: true });

      expect(apiFetch).toHaveBeenCalledWith(
        expect.stringContaining("unreadOnly=true"),
        expect.any(Object),
      );
    });
  });

  describe("markAsRead", () => {
    it("should mark a notification as read", async () => {
      (apiFetch as jest.Mock).mockResolvedValue({ success: true });

      const result = await markAsRead("notif-1");

      expect(apiFetch).toHaveBeenCalledWith("/notifications/notif-1/read", {
        method: "PUT",
      });
      expect(result.success).toBe(true);
    });
  });

  describe("markAllAsRead", () => {
    it("should mark all notifications as read", async () => {
      (apiFetch as jest.Mock).mockResolvedValue({ count: 5 });

      const result = await markAllAsRead();

      expect(apiFetch).toHaveBeenCalledWith("/notifications/read-all", {
        method: "PUT",
      });
      expect(result.count).toBe(5);
    });
  });

  describe("deleteNotification", () => {
    it("should delete a notification", async () => {
      (apiFetch as jest.Mock).mockResolvedValue({ success: true });

      const result = await deleteNotification("notif-1");

      expect(apiFetch).toHaveBeenCalledWith("/notifications/notif-1", {
        method: "DELETE",
      });
    });
  });

  describe("getUnreadCount", () => {
    it("should get unread notification count", async () => {
      (apiFetch as jest.Mock).mockResolvedValue({ count: 10 });

      const result = await getUnreadCount();

      expect(apiFetch).toHaveBeenCalledWith("/notifications/unread-count", {
        method: "GET",
      });
      expect(result.count).toBe(10);
    });
  });

  describe("updateSettings", () => {
    it("should update notification settings", async () => {
      const settings = {
        push: true,
        email: false,
        sms: false,
        quietHours: { start: "22:00", end: "07:00" },
      };

      (apiFetch as jest.Mock).mockResolvedValue(settings);

      const result = await updateSettings(settings);

      expect(apiFetch).toHaveBeenCalledWith("/notifications/settings", {
        method: "PUT",
        body: settings,
      });
    });
  });

  describe("getSettings", () => {
    it("should get notification settings", async () => {
      const mockSettings = {
        push: true,
        email: true,
        sms: false,
      };

      (apiFetch as jest.Mock).mockResolvedValue(mockSettings);

      const result = await getSettings();

      expect(apiFetch).toHaveBeenCalledWith("/notifications/settings", {
        method: "GET",
      });
      expect(result.push).toBe(true);
    });
  });

  describe("subscribeToTopic", () => {
    it("should subscribe to a topic", async () => {
      (apiFetch as jest.Mock).mockResolvedValue({ success: true });

      const result = await subscribeToTopic("project-updates");

      expect(apiFetch).toHaveBeenCalledWith("/notifications/topics/subscribe", {
        method: "POST",
        body: { topic: "project-updates" },
      });
    });
  });

  describe("unsubscribeFromTopic", () => {
    it("should unsubscribe from a topic", async () => {
      (apiFetch as jest.Mock).mockResolvedValue({ success: true });

      const result = await unsubscribeFromTopic("project-updates");

      expect(apiFetch).toHaveBeenCalledWith(
        "/notifications/topics/unsubscribe",
        {
          method: "POST",
          body: { topic: "project-updates" },
        },
      );
    });
  });
});
